-- All profession rank-up spells and recipes, aggregated from every real
-- profession trainer in the game (base + Master + Grand Master +
-- specialization trainers), deduplicated by spell, ordered low-to-high
-- skill rank within each profession. Values (cost/req level/req skill)
-- copied verbatim from whichever real trainer(s) already teach each spell.
--
-- Uses the trainer/trainer_spell/creature_default_trainer schema that
-- ObjectMgr::LoadTrainers() actually reads (confirmed via source) - NOT
-- the older npc_trainer table, which still holds real data but is no
-- longer read by the trainer-loading code in this AzerothCore version.
DELETE FROM `creature_default_trainer` WHERE `CreatureId` = 900200;
DELETE FROM `trainer_spell` WHERE `TrainerId` = 900200;
DELETE FROM `trainer` WHERE `Id` = 900200;

-- Type 2 = Tradeskill (see Trainer::Type in Trainer.h)


